// Helper to parse JSON from AI output
for (const item of items) {
  const response = item.json.output || item.json.text || "";

  // Try to find JSON block between first { and last }
  const start = response.indexOf('{');
  const end = response.lastIndexOf('}');

  if (start !== -1 && end !== -1) {
    try {
      const jsonStr = response.substring(start, end + 1);
      const data = JSON.parse(jsonStr);

      // Merge parsed data into item.json
      Object.assign(item.json, data);

      // Remove raw output
      delete item.json.output;
      delete item.json.text;
    } catch (e) {
      item.json.error = "Failed to parse JSON: " + e.message;
    }
  }
}

return items;

const binaryPropertyName = 'files';
const webhookBinary = $('Webhook').first().binary[binaryPropertyName];

return [
  {
    json: {
      ...items[0]?.json
    },
    binary: {
      [binaryPropertyName]: webhookBinary
    }
  }
];

